class PlantJournal:
    def __init__(self, plant_name, photo, waterings, description):
        self.plant_name = plant_name
        self.photo = photo
        self.waterings = waterings
        self.description = description
        self.date = "today"

    def add_watering(self, date):
        self.waterings.update({self.date: date})

    def delete_watering(self, date):
        if self.waterings.get(self.date):
            del self.waterings[self.date]

    def add_watering_by_date(self, date, waterings_time):
        if not self.waterings:
            self.waterings = {}
        if self.waterings.get(self.date):
            self.waterings[self.date].append(date)
        else:
            self.waterings[self.date] = [date]

    def __str__(self):
        return "Plant Name: {}\nPhoto: {}\nWaterings: {}\nDescription: {}".format(self.plant_name, self.photo, ", ".join(self.waterings), self.description)

    def update_description(self, new_description):
        self.description = new_description

    def change_waterings_time(self, date, new_time):
        if self.waterings.get(self.date):
            self.waterings[date].append(new_time)

